import{promises as c}from"node:fs";import{join as e}from"node:path";import{BookConfigSchema as f}from"@tavernos/core";import{readJson as p,writeJson as u}from"./fs-utils.js";import{bookDir as i,BOOKS_DIR as l}from"./paths.js";import{listChapters as m}from"./chapters.js";export async function listBookIds(r){const t=e(r,l);try{return(await c.readdir(t,{withFileTypes:!0})).filter(o=>o.isDirectory()).map(o=>o.name).sort()}catch{return[]}}export async function loadBookConfig(r,t){const n=await p(e(i(r,t),"book.json"));if(n===null)throw new Error(`Book not found: ${t}`);const o=f.safeParse(n);if(!o.success)throw new Error(`Invalid book config for ${t}`);return o.data}export async function saveBookConfig(r,t,n){await u(e(i(r,t),"book.json"),n)}export async function loadBookMeta(r,t){const n=await loadBookConfig(r,t),o=await m(r,t);let a=0;for(const s of o)a+=s.wordCount;return{config:n,chapterCount:o.length,totalWords:a,lastChapterAt:o.length>0?o[o.length-1].updatedAt:void 0,tags:[]}}
